/**
 * A pressure reading — derived state computed from cross-domain queries.
 *
 * Each pressure pairs an agent with an urge and stores the full gauge
 * data (inputs, calculation, config) as a self-describing audit trail.
 * Urgency is computed at read time from the stored gauge.
 */
export type Pressure = {
  agent_id: string;
  data: Gauge;
  id: string;
  updated_at: string;
  urge: Label;
};

/**
 * A pressure paired with its urge's prompt — the CTA that tells an
 * agent what to do about it.
 */
export type PressureReading = {
  cta: string;
  pressure: Pressure;
};

export type PressureResponse =
  | {
      data: ReadingsResponse;
      type: "readings";
    }
  | {
      data: AllReadingsResponse;
      type: "all-readings";
    };

/**
 * Compact pressure representation for ambient meta on every response.
 *
 * Carries just the urge name and a 0-100 urgency percentage — enough
 * for ambient awareness without the full gauge audit trail.
 * Full detail is available via `get_pressure` / `list_pressures`.
 */
export type PressureSummary = {
  percent: number;
  urge: Label;
};

