export type RecollectCalculation = {
  session_memory_factor: number;
  time_since_memory_factor: number;
  unconnected_experience_factor: number;
  working_memory_factor: number;
};

export type RecollectConfig = {
  memory_time_midpoint: number;
  memory_time_weight: number;
  session_memory_midpoint: number;
  session_memory_weight: number;
  unconnected_experience_weight: number;
  working_memory_midpoint: number;
  working_memory_weight: number;
};

/**
 * Recollect gauge: measures knowledge fragmentation pressure.
 *
 * Four factors weighted to produce a 0–1 urgency score:
 * - session_memory_factor (0.25): session-level memories (consolidation candidates)
 * - unconnected_experience_factor (0.25): experiences not linked by connections
 * - time_since_memory_factor (0.30): hours since last memory was added
 * - working_memory_factor (0.20): working-level memories (scratchpad overflow)
 */
export type RecollectGauge = {
  calculation: RecollectCalculation;
  config?: RecollectConfig;
  inputs: RecollectInputs;
};

export type RecollectInputs = {
  hours_since_last_memory: number;
  session_memory_count: number;
  total_experiences: number;
  unconnected_experiences: number;
  working_memory_count: number;
};

